import { utcToLocalInputValue } from '@linm-soft-org/linm-web-common-components';

export { localInputToISOWithOffset } from '@linm-soft-org/linm-web-common-components';

/**
 * Chuyển UTC ISO string → `YYYY-MM-DD` local để gán vào `<input type="date">`.
 * Rule: `form-datetime-local-utc.md` — cấm `.slice(0, 10)` trực tiếp trên UTC.
 */
export function toDateOnlyInputValue(value: string | null | undefined): string {
  if (!value) return '';
  const t = value.trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(t)) return t;
  return utcToLocalInputValue(t).slice(0, 10);
}
